```go
package main

import (
	"context"
	"fmt"
	"sync"
	"time"
)

// leaf simulates a long-running task that stops on ctx.Done().
func leaf(ctx context.Context, name string, wg *sync.WaitGroup) {
	defer wg.Done()
	for {
		select {
		case <-ctx.Done():
			fmt.Printf("%s: stopped (%v)\n", name, ctx.Err())
			return
		case <-time.After(100 * time.Millisecond):
			fmt.Printf("%s: tick\n", name)
		}
	}
}

// branch spawns children with a derived context.
func branch(ctx context.Context, name string, wg *sync.WaitGroup) {
	defer wg.Done()
	// Each branch creates its own child context.
	childCtx, cancel := context.WithCancel(ctx)
	defer cancel() // cancel children when branch exits

	var childWg sync.WaitGroup
	for i := 0; i < 2; i++ {
		childWg.Add(1)
		go leaf(childCtx, fmt.Sprintf("%s/leaf%d", name, i), &childWg)
	}
	childWg.Wait()
}

func main() {
	rootCtx, rootCancel := context.WithCancel(context.Background())

	var wg sync.WaitGroup
	for i := 0; i < 3; i++ {
		wg.Add(1)
		go branch(rootCtx, fmt.Sprintf("branch%d", i), &wg)
	}

	time.Sleep(350 * time.Millisecond)
	fmt.Println("--- cancelling root ---")
	rootCancel() // propagates to all branches and leaves

	wg.Wait()
	fmt.Println("all goroutines exited")
}
```

Context cancellation is hierarchical: cancelling a parent automatically cancels all derived children. The `defer cancel()` in `branch` is a safety net — it would fire anyway when the parent cancels, but it's good practice to always defer cancel to avoid leaks in code paths that exit early.

```go
package main

import (
	"context"
	"fmt"
	"net/http"
	"time"

	"github.com/google/uuid"
)

// Use unexported types as context keys to avoid collisions across packages.
type contextKey int

const (
	keyRequestID contextKey = iota
	keyUser
)

// RequestIDMiddleware injects a unique request ID into ctx.
func RequestIDMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		id := r.Header.Get("X-Request-ID")
		if id == "" {
			id = uuid.New().String()
		}
		ctx := context.WithValue(r.Context(), keyRequestID, id)
		w.Header().Set("X-Request-ID", id)
		next.ServeHTTP(w, r.WithContext(ctx))
	})
}

// AuthMiddleware extracts a user from a token and injects into ctx.
func AuthMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		token := r.Header.Get("Authorization")
		if token == "" {
			http.Error(w, "unauthorized", http.StatusUnauthorized)
			return
		}
		// In production: verify token and extract user.
		ctx := context.WithValue(r.Context(), keyUser, "alice")
		next.ServeHTTP(w, r.WithContext(ctx))
	})
}

// Helpers to extract values — keep access to keys in one package.
func RequestIDFromCtx(ctx context.Context) string {
	v, _ := ctx.Value(keyRequestID).(string)
	return v
}

func UserFromCtx(ctx context.Context) string {
	v, _ := ctx.Value(keyUser).(string)
	return v
}

func apiHandler(w http.ResponseWriter, r *http.Request) {
	rid := RequestIDFromCtx(r.Context())
	user := UserFromCtx(r.Context())
	fmt.Fprintf(w, "request=%s user=%s\n", rid, user)
}

func chain(h http.Handler, middlewares ...func(http.Handler) http.Handler) http.Handler {
	for i := len(middlewares) - 1; i >= 0; i-- {
		h = middlewares[i](h)
	}
	return h
}

func main() {
	handler := chain(http.HandlerFunc(apiHandler), RequestIDMiddleware, AuthMiddleware)
	srv := &http.Server{Addr: ":8080", Handler: handler, ReadTimeout: 5 * time.Second}
	fmt.Println("listening on :8080")
	_ = srv.ListenAndServe()
}
```

Critical rules for `context.WithValue`:
1. Always use an unexported package-local type as the key (not a string or int directly) to prevent collisions with other packages.
2. Context values are for request-scoped data only — not for passing optional parameters to functions.
3. Provide typed accessor functions (`RequestIDFromCtx`) so callers never touch keys directly.

```go
package main

import (
	"context"
	"errors"
	"fmt"
	"time"
)

// DB simulates a database layer.
type DB struct{}

// QueryUser simulates a slow query that respects ctx.
func (db *DB) QueryUser(ctx context.Context, id int) (string, error) {
	select {
	case <-time.After(200 * time.Millisecond):
		return fmt.Sprintf("user_%d", id), nil
	case <-ctx.Done():
		return "", fmt.Errorf("QueryUser: %w", ctx.Err())
	}
}

// Repository layer.
type UserRepo struct{ db *DB }

func (r *UserRepo) Get(ctx context.Context, id int) (string, error) {
	user, err := r.db.QueryUser(ctx, id)
	if err != nil {
		return "", fmt.Errorf("UserRepo.Get: %w", err)
	}
	return user, nil
}

// Service layer.
type UserService struct{ repo *UserRepo }

func (s *UserService) Profile(ctx context.Context, id int) (string, error) {
	user, err := s.repo.Get(ctx, id)
	if err != nil {
		return "", fmt.Errorf("UserService.Profile: %w", err)
	}
	return "profile:" + user, nil
}

// Handler / orchestrator.
func handleRequest(ctx context.Context, id int) error {
	svc := &UserService{repo: &UserRepo{db: &DB{}}}
	profile, err := svc.Profile(ctx, id)
	if err != nil {
		return fmt.Errorf("handleRequest: %w", err)
	}
	fmt.Println("result:", profile)
	return nil
}

func main() {
	// Case 1: generous timeout — succeeds.
	ctx1, cancel1 := context.WithTimeout(context.Background(), 500*time.Millisecond)
	defer cancel1()
	if err := handleRequest(ctx1, 1); err != nil {
		fmt.Println("error:", err)
	}

	// Case 2: tight timeout — cancels mid-query.
	ctx2, cancel2 := context.WithTimeout(context.Background(), 100*time.Millisecond)
	defer cancel2()
	if err := handleRequest(ctx2, 2); err != nil {
		fmt.Println("error:", err)
		fmt.Println("is deadline exceeded:", errors.Is(err, context.DeadlineExceeded))
	}
}
```

Error wrapping with `%w` preserves the full chain so `errors.Is(err, context.DeadlineExceeded)` works at any level of unwrapping. Each layer adds its name to the error message, giving a free call trace for debugging.

```go
package main

import (
	"context"
	"fmt"
	"log"
	"net/http"
	"runtime/debug"
	"time"
)

// TimeoutMiddleware wraps each request with a deadline.
func TimeoutMiddleware(timeout time.Duration) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			ctx, cancel := context.WithTimeout(r.Context(), timeout)
			defer cancel()
			next.ServeHTTP(w, r.WithContext(ctx))
		})
	}
}

// RecoveryMiddleware catches panics and returns 500.
func RecoveryMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		defer func() {
			if rec := recover(); rec != nil {
				log.Printf("panic: %v\n%s", rec, debug.Stack())
				http.Error(w, "internal server error", http.StatusInternalServerError)
			}
		}()
		next.ServeHTTP(w, r)
	})
}

// slowHandler simulates work that may outlive the context deadline.
func slowHandler(w http.ResponseWriter, r *http.Request) {
	ctx := r.Context()
	select {
	case <-time.After(2 * time.Second):
		fmt.Fprintln(w, "done")
	case <-ctx.Done():
		// By the time we get here, ResponseWriter may already be committed.
		http.Error(w, "request timed out", http.StatusGatewayTimeout)
	}
}

func main() {
	mux := http.NewServeMux()
	mux.HandleFunc("/slow", slowHandler)
	mux.HandleFunc("/panic", func(w http.ResponseWriter, r *http.Request) {
		panic("intentional panic")
	})

	handler := RecoveryMiddleware(TimeoutMiddleware(500*time.Millisecond)(mux))

	srv := &http.Server{
		Addr:         ":8080",
		Handler:      handler,
		ReadTimeout:  5 * time.Second,
		WriteTimeout: 5 * time.Second,
	}
	log.Println("server starting on :8080")
	log.Fatal(srv.ListenAndServe())
}
```

Note: the server-level `WriteTimeout` must be longer than the per-request timeout, otherwise the server may kill the connection before the handler's timeout fires. The context timeout only affects goroutines that cooperate with `ctx.Done()` — blocking syscalls need OS-level deadlines via `SetDeadline`.

```go
package main

import (
	"bytes"
	"context"
	"errors"
	"fmt"
	"io"
	"time"
)

// readWithContext reads up to len(buf) bytes from r,
// aborting if ctx is cancelled before the read completes.
// Works by running the blocking Read in a goroutine.
func readWithContext(ctx context.Context, r io.Reader, buf []byte) (int, error) {
	type result struct {
		n   int
		err error
	}
	ch := make(chan result, 1) // buffered: goroutine never leaks if we return early

	go func() {
		n, err := r.Read(buf)
		ch <- result{n, err}
	}()

	select {
	case res := <-ch:
		return res.n, res.err
	case <-ctx.Done():
		return 0, fmt.Errorf("readWithContext: %w", ctx.Err())
	}
}

// slowReader simulates a reader that takes time.
type slowReader struct {
	data  []byte
	delay time.Duration
}

func (s *slowReader) Read(p []byte) (int, error) {
	time.Sleep(s.delay)
	n := copy(p, s.data)
	if n == 0 {
		return 0, io.EOF
	}
	return n, nil
}

func main() {
	// Case 1: fast enough.
	ctx1, cancel1 := context.WithTimeout(context.Background(), 500*time.Millisecond)
	defer cancel1()
	reader1 := &slowReader{data: []byte("hello world"), delay: 100 * time.Millisecond}
	buf := make([]byte, 64)
	n, err := readWithContext(ctx1, reader1, buf)
	fmt.Printf("read %d bytes: %q err=%v\n", n, buf[:n], err)

	// Case 2: too slow — context deadline exceeded.
	ctx2, cancel2 := context.WithTimeout(context.Background(), 50*time.Millisecond)
	defer cancel2()
	reader2 := &slowReader{data: []byte("slow data"), delay: 200 * time.Millisecond}
	_, err = readWithContext(ctx2, reader2, bytes.NewBuffer(nil).Bytes())
	fmt.Println("expected error:", err)
	fmt.Println("is DeadlineExceeded:", errors.Is(err, context.DeadlineExceeded))
}
```

The buffered channel (capacity 1) is crucial: if we return due to ctx cancellation, the goroutine still completes its `Read` and sends to `ch` — the buffer absorbs the send so the goroutine exits cleanly. Without the buffer, the goroutine would leak. This pattern applies to any blocking call (net.Conn.Read, file reads, etc.).

```go
package main

import (
	"fmt"
	"sync"
)

// MutexMap wraps a standard map with a RWMutex.
// Best when: writes are frequent, key set changes often.
type MutexMap struct {
	mu sync.RWMutex
	m  map[string]int
}

func NewMutexMap() *MutexMap { return &MutexMap{m: make(map[string]int)} }

func (mm *MutexMap) Store(k string, v int) {
	mm.mu.Lock()
	defer mm.mu.Unlock()
	mm.m[k] = v
}

func (mm *MutexMap) Load(k string) (int, bool) {
	mm.mu.RLock()
	defer mm.mu.RUnlock()
	v, ok := mm.m[k]
	return v, ok
}

func (mm *MutexMap) Delete(k string) {
	mm.mu.Lock()
	defer mm.mu.Unlock()
	delete(mm.m, k)
}

// SyncMap wraps sync.Map.
// Best when: key set is stable and reads dominate (many goroutines read the same keys).
type SyncMap struct{ m sync.Map }

func (sm *SyncMap) Store(k string, v int)        { sm.m.Store(k, v) }
func (sm *SyncMap) Load(k string) (int, bool) {
	v, ok := sm.m.Load(k)
	if !ok {
		return 0, false
	}
	return v.(int), true
}
func (sm *SyncMap) Delete(k string) { sm.m.Delete(k) }

func demo() {
	var wg sync.WaitGroup
	mm := NewMutexMap()
	sm := &SyncMap{}

	// Concurrent writes and reads on both maps.
	for i := 0; i < 100; i++ {
		i := i
		wg.Add(2)
		go func() {
			defer wg.Done()
			key := fmt.Sprintf("key%d", i%10)
			mm.Store(key, i)
			v, _ := mm.Load(key)
			_ = v
		}()
		go func() {
			defer wg.Done()
			key := fmt.Sprintf("key%d", i%10)
			sm.Store(key, i)
			v, _ := sm.Load(key)
			_ = v
		}()
	}
	wg.Wait()
	fmt.Println("both maps safe")
}

func main() { demo() }
```

Decision guide:
- **`sync.Map`**: stable key set (written once, read many times); many goroutines sharing the same keys. It uses a copy-on-write read path to avoid lock contention on reads.
- **`mutex + map`**: growing key sets, frequent writes, when you need `len()` or iteration — `sync.Map` makes these awkward. `sync.RWMutex` gives free concurrent reads with a single writer.
- Never embed `sync.Map` by value in structs; always use it as a field.

```go
package main

import (
	"fmt"
	"sync"
)

// ExpensiveResource simulates a resource that should only be initialized once.
type ExpensiveResource struct {
	data string
}

func newExpensiveResource() *ExpensiveResource {
	fmt.Println("initializing resource...")
	return &ExpensiveResource{data: "loaded"}
}

// BROKEN: double-checked locking — UNSAFE in Go.
// The Go memory model does not guarantee that a non-nil pointer
// implies the struct it points to is fully initialized to other goroutines.
type BrokenSingleton struct {
	mu       sync.Mutex
	instance *ExpensiveResource
}

func (s *BrokenSingleton) Get() *ExpensiveResource {
	if s.instance != nil { // unsynchronized read — DATA RACE
		return s.instance
	}
	s.mu.Lock()
	defer s.mu.Unlock()
	if s.instance == nil {
		s.instance = newExpensiveResource()
	}
	return s.instance
}

// CORRECT: sync.Once — guaranteed single initialization, safe for all goroutines.
type Singleton struct {
	once     sync.Once
	instance *ExpensiveResource
}

func (s *Singleton) Get() *ExpensiveResource {
	s.once.Do(func() {
		s.instance = newExpensiveResource()
	})
	return s.instance
}

// Package-level singleton pattern.
var (
	globalOnce sync.Once
	global     *ExpensiveResource
)

func GlobalResource() *ExpensiveResource {
	globalOnce.Do(func() {
		global = newExpensiveResource()
	})
	return global
}

func main() {
	s := &Singleton{}
	var wg sync.WaitGroup
	for i := 0; i < 10; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			r := s.Get()
			_ = r
		}()
	}
	wg.Wait()
	fmt.Println("resource:", s.Get().data) // "loaded"

	// Verify GlobalResource is also initialized once.
	fmt.Println("global:", GlobalResource().data)
}
```

`sync.Once.Do` guarantees: (1) the function runs exactly once across all concurrent callers; (2) all goroutines that call `Do` after the function has run observe the fully initialized value — a happens-before relationship is established. After `once.Do` returns, `s.instance` is safe to read without a lock.

```go
package main

import (
	"container/list"
	"fmt"
	"sync"
)

type entry struct {
	key   string
	value any
}

type LRUCache struct {
	mu       sync.RWMutex
	cap      int
	list     *list.List
	elements map[string]*list.Element
}

func NewLRUCache(capacity int) *LRUCache {
	return &LRUCache{
		cap:      capacity,
		list:     list.New(),
		elements: make(map[string]*list.Element, capacity),
	}
}

// Get returns (value, true) and marks the key as recently used.
func (c *LRUCache) Get(key string) (any, bool) {
	c.mu.Lock() // full lock: MoveToFront modifies state
	defer c.mu.Unlock()
	if elem, ok := c.elements[key]; ok {
		c.list.MoveToFront(elem)
		return elem.Value.(*entry).value, true
	}
	return nil, false
}

// Put inserts or updates a key, evicting the LRU entry if at capacity.
func (c *LRUCache) Put(key string, value any) {
	c.mu.Lock()
	defer c.mu.Unlock()

	if elem, ok := c.elements[key]; ok {
		c.list.MoveToFront(elem)
		elem.Value.(*entry).value = value
		return
	}

	if c.list.Len() == c.cap {
		// Evict least recently used (back of list).
		old := c.list.Back()
		if old != nil {
			c.list.Remove(old)
			delete(c.elements, old.Value.(*entry).key)
		}
	}

	elem := c.list.PushFront(&entry{key: key, value: value})
	c.elements[key] = elem
}

// Len returns the current number of entries.
func (c *LRUCache) Len() int {
	c.mu.RLock()
	defer c.mu.RUnlock()
	return c.list.Len()
}

func main() {
	cache := NewLRUCache(3)
	cache.Put("a", 1)
	cache.Put("b", 2)
	cache.Put("c", 3)

	v, _ := cache.Get("a") // promotes "a" to front
	fmt.Println("a:", v)

	cache.Put("d", 4) // evicts "b" (LRU)
	_, ok := cache.Get("b")
	fmt.Println("b exists:", ok) // false

	var wg sync.WaitGroup
	for i := 0; i < 10; i++ {
		i := i
		wg.Add(1)
		go func() {
			defer wg.Done()
			cache.Put(fmt.Sprintf("k%d", i), i)
		}()
	}
	wg.Wait()
	fmt.Println("len:", cache.Len())
}
```

```go
package main

import (
	"fmt"
	"sync"
)

// BROKEN: calling wg.Add inside the goroutine is a race.
// wg.Wait() may return before all goroutines have called Add.
func brokenPattern(items []int) {
	var wg sync.WaitGroup
	for _, item := range items {
		go func(v int) {
			wg.Add(1) // WRONG: wg.Wait() may already be done
			defer wg.Done()
			fmt.Println(v)
		}(item)
	}
	wg.Wait() // may return immediately with 0 goroutines registered
}

// FIXED: always call wg.Add before launching the goroutine.
func correctPattern(items []int) {
	var wg sync.WaitGroup
	for _, item := range items {
		wg.Add(1) // increment BEFORE go func
		go func(v int) {
			defer wg.Done()
			fmt.Println(v)
		}(item)
	}
	wg.Wait()
}

// PATTERN: pass *sync.WaitGroup to a function that spawns goroutines.
func spawnWorkers(wg *sync.WaitGroup, items []int) {
	for _, item := range items {
		wg.Add(1)
		go func(v int) {
			defer wg.Done()
			fmt.Println("worker:", v)
		}(item)
	}
}

// PATTERN: WaitGroup + result channel combination.
func collectResults(items []int) []int {
	var wg sync.WaitGroup
	results := make(chan int, len(items))

	for _, item := range items {
		wg.Add(1)
		go func(v int) {
			defer wg.Done()
			results <- v * 2
		}(item)
	}

	// Close results after all goroutines finish.
	go func() {
		wg.Wait()
		close(results)
	}()

	var out []int
	for r := range results {
		out = append(out, r)
	}
	return out
}

func main() {
	items := []int{1, 2, 3, 4, 5}
	fmt.Println("=== correct pattern ===")
	correctPattern(items)

	var wg sync.WaitGroup
	spawnWorkers(&wg, items)
	wg.Wait()

	fmt.Println("=== results:", collectResults(items))
}
```

The rule: `wg.Add(n)` must happen-before `wg.Wait()`. The only safe place is before the `go` statement, in the same goroutine that calls `Wait`, or while holding a lock that the Wait goroutine also holds before calling Wait.

```go
package main

import (
	"fmt"
	"sync"
	"sync/atomic"
	"unsafe"
)

type node[T any] struct {
	val  T
	next unsafe.Pointer // *node[T]
}

// LockFreeStack is a Treiber stack — lock-free LIFO using CAS.
type LockFreeStack[T any] struct {
	head unsafe.Pointer // *node[T]
}

// Push adds an element to the top of the stack.
func (s *LockFreeStack[T]) Push(val T) {
	newNode := &node[T]{val: val}
	for {
		old := atomic.LoadPointer(&s.head)
		newNode.next = old
		if atomic.CompareAndSwapPointer(&s.head, old, unsafe.Pointer(newNode)) {
			return
		}
		// CAS failed: another goroutine modified head; retry.
	}
}

// Pop removes and returns the top element.
// Returns zero value and false if empty.
func (s *LockFreeStack[T]) Pop() (T, bool) {
	for {
		old := atomic.LoadPointer(&s.head)
		if old == nil {
			var zero T
			return zero, false
		}
		top := (*node[T])(old)
		next := atomic.LoadPointer(&top.next)
		if atomic.CompareAndSwapPointer(&s.head, old, next) {
			return top.val, true
		}
	}
}

func main() {
	s := &LockFreeStack[int]{}
	var wg sync.WaitGroup

	// Concurrent pushes.
	for i := 0; i < 1000; i++ {
		i := i
		wg.Add(1)
		go func() {
			defer wg.Done()
			s.Push(i)
		}()
	}
	wg.Wait()

	// Drain.
	count := 0
	for {
		_, ok := s.Pop()
		if !ok {
			break
		}
		count++
	}
	fmt.Println("popped:", count) // should be 1000
}
```

This is the Treiber stack algorithm. The ABA problem (where the pointer value matches but the node has been recycled) can occur if nodes are reused. In Go, the GC prevents actual ABA since collected nodes get new addresses — but in production, test with `-race` and consider `golang.org/x/sync/atomic` for higher-level primitives.

```go
package parse_test

import (
	"errors"
	"strconv"
	"testing"
)

// ParseInt wraps strconv.Atoi with a domain-specific error.
func ParseInt(s string) (int, error) {
	if s == "" {
		return 0, errors.New("empty string")
	}
	v, err := strconv.Atoi(s)
	if err != nil {
		return 0, fmt.Errorf("invalid integer %q: %w", s, err)
	}
	return v, nil
}

func TestParseInt(t *testing.T) {
	t.Parallel()

	cases := []struct {
		name    string
		input   string
		want    int
		wantErr bool
	}{
		{name: "positive integer", input: "42", want: 42},
		{name: "negative integer", input: "-7", want: -7},
		{name: "zero", input: "0", want: 0},
		{name: "max int32", input: "2147483647", want: 2147483647},
		{name: "empty string", input: "", wantErr: true},
		{name: "non-numeric", input: "abc", wantErr: true},
		{name: "float string", input: "3.14", wantErr: true},
		{name: "leading spaces", input: " 5", wantErr: true},
		{name: "hex string", input: "0xFF", wantErr: true},
	}

	for _, tc := range cases {
		tc := tc // capture range variable (pre-Go 1.22)
		t.Run(tc.name, func(t *testing.T) {
			t.Parallel() // each subtest runs concurrently

			got, err := ParseInt(tc.input)

			if tc.wantErr {
				if err == nil {
					t.Errorf("ParseInt(%q) = %d, want error", tc.input, got)
				}
				return
			}

			if err != nil {
				t.Fatalf("ParseInt(%q) unexpected error: %v", tc.input, err)
			}
			if got != tc.want {
				t.Errorf("ParseInt(%q) = %d, want %d", tc.input, got, tc.want)
			}
		})
	}
}
```

Best practices demonstrated:
- `tc := tc` inside the loop prevents the classic loop variable capture bug (still needed pre-Go 1.22).
- `t.Parallel()` at both the top level and subtest level maximises test throughput.
- `t.Fatalf` for setup failures (can't continue), `t.Errorf` for assertion failures (continue checking).
- Test names use descriptive phrases, not `case1`, `case2` — `go test -run TestParseInt/negative_integer` filters cleanly.

```go
package main

import (
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
)

// User handler — the code under test.
type User struct {
	Name  string `json:"name"`
	Email string `json:"email"`
}

func CreateUserHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
		return
	}
	if r.Header.Get("Content-Type") != "application/json" {
		http.Error(w, "content-type must be application/json", http.StatusUnsupportedMediaType)
		return
	}
	var u User
	if err := json.NewDecoder(r.Body).Decode(&u); err != nil {
		http.Error(w, "invalid body", http.StatusBadRequest)
		return
	}
	if u.Name == "" {
		http.Error(w, "name required", http.StatusUnprocessableEntity)
		return
	}
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusCreated)
	json.NewEncoder(w).Encode(u)
}

func TestCreateUserHandler(t *testing.T) {
	t.Parallel()
	cases := []struct {
		name       string
		method     string
		body       string
		contentType string
		wantStatus int
		wantName   string
	}{
		{
			name:        "valid request",
			method:      http.MethodPost,
			body:        `{"name":"Alice","email":"alice@example.com"}`,
			contentType: "application/json",
			wantStatus:  http.StatusCreated,
			wantName:    "Alice",
		},
		{
			name:        "wrong method",
			method:      http.MethodGet,
			body:        "",
			contentType: "application/json",
			wantStatus:  http.StatusMethodNotAllowed,
		},
		{
			name:        "missing content-type",
			method:      http.MethodPost,
			body:        `{"name":"Bob"}`,
			contentType: "text/plain",
			wantStatus:  http.StatusUnsupportedMediaType,
		},
		{
			name:        "empty name",
			method:      http.MethodPost,
			body:        `{"name":""}`,
			contentType: "application/json",
			wantStatus:  http.StatusUnprocessableEntity,
		},
	}

	for _, tc := range cases {
		tc := tc
		t.Run(tc.name, func(t *testing.T) {
			t.Parallel()
			req := httptest.NewRequest(tc.method, "/users", strings.NewReader(tc.body))
			req.Header.Set("Content-Type", tc.contentType)
			rec := httptest.NewRecorder()

			CreateUserHandler(rec, req)

			res := rec.Result()
			defer res.Body.Close()

			if res.StatusCode != tc.wantStatus {
				t.Errorf("status = %d, want %d", res.StatusCode, tc.wantStatus)
			}
			if tc.wantName != "" {
				if ct := res.Header.Get("Content-Type"); !strings.Contains(ct, "application/json") {
					t.Errorf("Content-Type = %q, want application/json", ct)
				}
				var u User
				if err := json.NewDecoder(res.Body).Decode(&u); err != nil {
					t.Fatal("decode response:", err)
				}
				if u.Name != tc.wantName {
					t.Errorf("name = %q, want %q", u.Name, tc.wantName)
				}
			}
		})
	}
}
