```go
package main

import (
	"errors"
	"fmt"
	"io"
)

// Go's io package already demonstrates interface composition.
// Here we build a custom hierarchy to illustrate the principle.

// Namer can return a name.
type Namer interface {
	Name() string
}

// Sizer can return a size.
type Sizer interface {
	Size() int64
}

// Metadata composes Namer and Sizer.
type Metadata interface {
	Namer
	Sizer
}

// ReadableStore composes io.Reader with Metadata.
type ReadableStore interface {
	io.Reader
	Metadata
}

// MemFile is an in-memory file satisfying ReadableStore + io.Seeker + io.Writer.
type MemFile struct {
	name   string
	data   []byte
	offset int64
}

func NewMemFile(name string) *MemFile {
	return &MemFile{name: name}
}

func (f *MemFile) Name() string  { return f.name }
func (f *MemFile) Size() int64  { return int64(len(f.data)) }

func (f *MemFile) Read(p []byte) (int, error) {
	if f.offset >= int64(len(f.data)) {
		return 0, io.EOF
	}
	n := copy(p, f.data[f.offset:])
	f.offset += int64(n)
	return n, nil
}

func (f *MemFile) Write(p []byte) (int, error) {
	f.data = append(f.data, p...)
	return len(p), nil
}

func (f *MemFile) Seek(offset int64, whence int) (int64, error) {
	var abs int64
	switch whence {
	case io.SeekStart:
		abs = offset
	case io.SeekCurrent:
		abs = f.offset + offset
	case io.SeekEnd:
		abs = int64(len(f.data)) + offset
	default:
		return 0, errors.New("invalid whence")
	}
	if abs < 0 {
		return 0, errors.New("negative position")
	}
	f.offset = abs
	return abs, nil
}

// printInfo accepts only the composed interface — compile-time guarantee.
func printInfo(s ReadableStore) {
	fmt.Printf("file: %s, size: %d bytes\n", s.Name(), s.Size())
}

func main() {
	f := NewMemFile("example.txt")
	f.Write([]byte("hello, world"))

	printInfo(f) // MemFile satisfies ReadableStore

	// Seek back and read.
	f.Seek(0, io.SeekStart)
	buf := make([]byte, 5)
	n, _ := f.Read(buf)
	fmt.Printf("read: %q\n", buf[:n])

	// Demonstrate io.ReadWriteSeeker satisfaction.
	var _ io.ReadWriteSeeker = f // compile-time interface check
}
```

Interface composition in Go is purely additive — no inheritance, no method resolution order. A type satisfies a composed interface if it implements all methods of all embedded interfaces. The `var _ InterfaceName = value` idiom is a compile-time assertion that `value` implements `InterfaceName`.

```go
package main

import (
	"fmt"
	"time"
)

// Base types with their own methods.
type Timestamps struct {
	CreatedAt time.Time
	UpdatedAt time.Time
}

func (t *Timestamps) Touch() {
	t.UpdatedAt = time.Now()
}

func (t Timestamps) Age() time.Duration {
	return time.Since(t.CreatedAt)
}

type ID struct {
	Value int64
}

func (id ID) String() string {
	return fmt.Sprintf("#%d", id.Value)
}

// User embeds ID and Timestamps — all their methods are promoted.
type User struct {
	ID
	Timestamps
	Name  string
	Email string
}

// Article also embeds Timestamps.
type Article struct {
	ID
	Timestamps
	Title string
}

// Stringer interface — fmt.Stringer.
type Stringer interface {
	String() string
}

// User satisfies fmt.Stringer via embedding (ID.String is promoted),
// but we can override it.
func (u User) String() string {
	return fmt.Sprintf("User(%s, %s)", u.ID.String(), u.Name) // explicit call to embedded
}

// Touchable is satisfied by anything with a Touch method.
type Touchable interface {
	Touch()
}

func updateTimestamp(t Touchable) {
	t.Touch()
}

func main() {
	u := &User{
		ID:         ID{Value: 42},
		Timestamps: Timestamps{CreatedAt: time.Now().Add(-72 * time.Hour)},
		Name:       "Alice",
		Email:      "alice@example.com",
	}

	// Promoted methods.
	u.Touch()                             // Timestamps.Touch via promotion
	fmt.Println(u.Age().Round(time.Hour)) // ~72h
	fmt.Println(u)                        // User(#42, Alice)

	// *User satisfies Touchable because *Timestamps.Touch is promoted.
	updateTimestamp(u)

	// Access embedded fields directly.
	fmt.Println(u.UpdatedAt.Format(time.RFC3339))

	// NOT inheritance: User does not "extend" ID.
	// You can still access the embedded type explicitly.
	fmt.Println(u.ID.String())  // #42
	fmt.Println(u.ID.Value)     // 42
}
```

Key distinction from inheritance: embedding is *delegation*, not subtyping. A `*User` is not a `*Timestamps` — you cannot pass a `*User` where a `*Timestamps` is expected. But all methods of `Timestamps` are accessible on `User` without repetition. Method promotion also means `*User` automatically satisfies any interface that `*Timestamps` satisfies, which is the Go substitute for interface inheritance.

