package main

import (
	"encoding/json"
	"io"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
)

// Middleware under test.
func loggingMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("X-Served-By", "test-server")
		next.ServeHTTP(w, r)
	})
}

func authMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if r.Header.Get("Authorization") == "" {
			http.Error(w, "unauthorized", http.StatusUnauthorized)
			return
		}
		next.ServeHTTP(w, r)
	})
}

// Handler under test.
func echoHandler(w http.ResponseWriter, r *http.Request) {
	body, _ := io.ReadAll(r.Body)
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{
		"echo":   string(body),
		"method": r.Method,
	})
}

func buildTestServer() *httptest.Server {
	mux := http.NewServeMux()
	mux.HandleFunc("/echo", echoHandler)
	handler := loggingMiddleware(authMiddleware(mux))
	return httptest.NewServer(handler)
}

func TestIntegration_EchoEndpoint(t *testing.T) {
	srv := buildTestServer()
	defer srv.Close() // releases port and closes listener

	client := srv.Client() // pre-configured to talk to the test server

	cases := []struct {
		name       string
		auth       string
		body       string
		wantStatus int
		wantEcho   string
	}{
		{
			name:       "authenticated echo",
			auth:       "Bearer token123",
			body:       "hello world",
			wantStatus: http.StatusOK,
			wantEcho:   "hello world",
		},
		{
			name:       "missing auth",
			auth:       "",
			body:       "data",
			wantStatus: http.StatusUnauthorized,
		},
	}

	for _, tc := range cases {
		tc := tc
		t.Run(tc.name, func(t *testing.T) {
			req, _ := http.NewRequest(http.MethodPost, srv.URL+"/echo", strings.NewReader(tc.body))
			if tc.auth != "" {
				req.Header.Set("Authorization", tc.auth)
			}

			resp, err := client.Do(req)
			if err != nil {
				t.Fatal(err)
			}
			defer resp.Body.Close()

			if resp.StatusCode != tc.wantStatus {
				t.Errorf("status = %d, want %d", resp.StatusCode, tc.wantStatus)
			}
			// Check middleware header on all responses.
			if got := resp.Header.Get("X-Served-By"); got != "test-server" {
				t.Errorf("X-Served-By = %q, want test-server", got)
			}
			if tc.wantEcho != "" {
				var result map[string]string
				json.NewDecoder(resp.Body).Decode(&result)
				if result["echo"] != tc.wantEcho {
					t.Errorf("echo = %q, want %q", result["echo"], tc.wantEcho)
				}
			}
		})
	}
}
```

`httptest.NewServer` binds a real port on localhost, making this a true integration test — all middleware, routing, and HTTP framing is exercised. `srv.Client()` returns a client pre-wired to the server's listener, so TLS tests also work with `httptest.NewTLSServer` without certificate trust issues.

