package mydb_test

import (
	"database/sql"
	"fmt"
	"os"
	"testing"
	"time"

	_ "github.com/lib/pq"
)

// testDB is the shared connection pool for the entire test binary.
var testDB *sql.DB

// TestMain runs before any test in the package.
// It initialises shared resources and tears them down after tests complete.
func TestMain(m *testing.M) {
	// Setup.
	dsn := os.Getenv("TEST_DATABASE_URL")
	if dsn == "" {
		dsn = "postgres://localhost/testdb?sslmode=disable"
	}

	var err error
	testDB, err = sql.Open("postgres", dsn)
	if err != nil {
		fmt.Fprintf(os.Stderr, "open db: %v\n", err)
		os.Exit(1)
	}
	testDB.SetMaxOpenConns(10)
	testDB.SetConnMaxLifetime(time.Minute)

	if err = testDB.Ping(); err != nil {
		fmt.Fprintf(os.Stderr, "ping db: %v\n", err)
		os.Exit(1)
	}

	if err = migrateTestSchema(testDB); err != nil {
		fmt.Fprintf(os.Stderr, "migrate: %v\n", err)
		os.Exit(1)
	}

	// Run all tests in the package.
	code := m.Run()

	// Teardown.
	testDB.Exec("DROP SCHEMA test CASCADE")
	testDB.Close()

	os.Exit(code)
}

func migrateTestSchema(db *sql.DB) error {
	_, err := db.Exec(`
		CREATE TABLE IF NOT EXISTS users (
			id   SERIAL PRIMARY KEY,
			name TEXT NOT NULL
		)
	`)
	return err
}

// Helper: create an isolated test-specific DB state using subtransactions.
func withTx(t *testing.T, fn func(tx *sql.Tx)) {
	t.Helper()
	tx, err := testDB.Begin()
	if err != nil {
		t.Fatal("begin tx:", err)
	}
	defer tx.Rollback() // always roll back — test isolation
	fn(tx)
}

// Example test using the shared DB via a rolled-back transaction.
func TestCreateUser(t *testing.T) {
	withTx(t, func(tx *sql.Tx) {
		_, err := tx.Exec("INSERT INTO users(name) VALUES($1)", "alice")
		if err != nil {
			t.Fatal(err)
		}
		var count int
		if err := tx.QueryRow("SELECT COUNT(*) FROM users WHERE name=$1", "alice").Scan(&count); err != nil {
			t.Fatal(err)
		}
		if count != 1 {
			t.Errorf("count = %d, want 1", count)
		}
		// tx.Rollback() called by defer in withTx — DB state is clean for next test.
	})
}
```

`TestMain` is the only correct place for package-level test setup/teardown in Go. The deferred `Rollback` pattern in `withTx` gives each test a clean slate without truncating tables between tests — it's O(1) regardless of how much data the test inserts.

```go
package main

import (
	"context"
	"fmt"
	"strings"
	"testing"
)

// Stage is anything that transforms a stream of strings.
type Stage interface {
	Process(ctx context.Context, in <-chan string) <-chan string
}

// UpperStage converts strings to uppercase.
type UpperStage struct{}

func (s *UpperStage) Process(ctx context.Context, in <-chan string) <-chan string {
	out := make(chan string)
	go func() {
		defer close(out)
		for v := range in {
			select {
			case out <- strings.ToUpper(v):
			case <-ctx.Done():
				return
			}
		}
	}()
	return out
}

// FilterStage drops values shorter than minLen.
type FilterStage struct{ minLen int }

func (s *FilterStage) Process(ctx context.Context, in <-chan string) <-chan string {
	out := make(chan string)
	go func() {
		defer close(out)
		for v := range in {
			if len(v) < s.minLen {
				continue
			}
			select {
			case out <- v:
			case <-ctx.Done():
				return
			}
		}
	}()
	return out
}

// Pipeline chains multiple stages.
func Pipeline(ctx context.Context, source <-chan string, stages ...Stage) <-chan string {
	current := source
	for _, s := range stages {
		current = s.Process(ctx, current)
	}
	return current
}

// helper: create a source channel from a slice (for tests).
func fromSlice(ctx context.Context, items ...string) <-chan string {
	ch := make(chan string)
	go func() {
		defer close(ch)
		for _, item := range items {
			select {
			case ch <- item:
			case <-ctx.Done():
				return
			}
		}
	}()
	return ch
}

func TestUpperStage(t *testing.T) {
	ctx := context.Background()
	stage := &UpperStage{}
	out := stage.Process(ctx, fromSlice(ctx, "hello", "world"))
	var got []string
	for v := range out {
		got = append(got, v)
	}
	expect := []string{"HELLO", "WORLD"}
	for i, v := range expect {
		if got[i] != v {
			t.Errorf("got[%d] = %q, want %q", i, got[i], v)
		}
	}
}

func TestFilterStage(t *testing.T) {
	ctx := context.Background()
	stage := &FilterStage{minLen: 4}
	out := stage.Process(ctx, fromSlice(ctx, "hi", "hello", "ok", "world"))
	var got []string
	for v := range out {
		got = append(got, v)
	}
	if len(got) != 2 || got[0] != "hello" || got[1] != "world" {
		t.Errorf("unexpected: %v", got)
	}
}

func main() {
	ctx := context.Background()
	source := fromSlice(ctx, "go", "hello", "hi", "concurrency", "ok")
	result := Pipeline(ctx, source,
		&FilterStage{minLen: 3},
		&UpperStage{},
	)
	for v := range result {
		fmt.Println(v)
	}
}
```

The `Stage` interface makes each pipeline component independently testable — `fromSlice` is the test fixture that replaces real data sources. Tests for `UpperStage` and `FilterStage` are hermetic: they don't depend on each other.

